-- Exact weapon Essence rank data for Arknights: Endfield.
-- Sources: the published rank 1-9 tables on each linked weapon page.
-- Checked: 2026-06-05. No interpolated or estimated values are included.
-- Run supabase/schema.sql first, then run this file.

begin;

create table if not exists public.weapon_essence_profiles (
    weapon_key text primary key references public.weapons(weapon_key) on delete cascade,
    primary_label text,
    primary_values numeric[],
    primary_is_percent boolean not null default false,
    secondary_label text,
    secondary_values numeric[],
    secondary_is_percent boolean not null default false,
    skill_name text,
    skill_descriptions jsonb not null default '[]'::jsonb,
    primary_base_ranks smallint[] not null default ARRAY[1, 2, 2, 3, 3]::smallint[],
    secondary_base_ranks smallint[] not null default ARRAY[1, 1, 2, 2, 3]::smallint[],
    primary_max_essence smallint not null default 6,
    secondary_max_essence smallint not null default 6,
    skill_max_essence smallint not null default 4,
    source_url text,
    source_note text,
    verified boolean not null default false,
    created_at timestamptz not null default now(),
    updated_at timestamptz not null default now(),
    constraint weapon_essence_primary_values_length check (primary_values is null or cardinality(primary_values) = 9),
    constraint weapon_essence_secondary_values_length check (secondary_values is null or cardinality(secondary_values) = 9),
    constraint weapon_essence_skill_descriptions_length check (jsonb_array_length(skill_descriptions) in (0, 9)),
    constraint weapon_essence_limits_check check (primary_max_essence between 0 and 8 and secondary_max_essence between 0 and 8 and skill_max_essence between 0 and 8)
);

alter table public.weapon_essence_profiles enable row level security;
drop policy if exists "Public read weapon essence profiles" on public.weapon_essence_profiles;
create policy "Public read weapon essence profiles" on public.weapon_essence_profiles for select using (true);

insert into public.weapon_essence_profiles (
    weapon_key, primary_label, primary_values, primary_is_percent,
    secondary_label, secondary_values, secondary_is_percent,
    skill_name, skill_descriptions, primary_base_ranks, secondary_base_ranks,
    primary_max_essence, secondary_max_essence, skill_max_essence,
    source_url, source_note, verified, updated_at
) values
